-- Sub-wave 3C: bulk REVOKE EXECUTE on SECURITY DEFINER functions in public,
-- with a tight re-GRANT to 'authenticated' for the React app's whitelisted
-- supabase.rpc() targets.
DO $$
DECLARE
  fn record;
  whitelist text[] := ARRAY['accept_pk_battle','accept_private_call','accept_seat_invitation','add_beans_to_user','add_coins_to_user','add_diamonds_to_user','admin_add_agency_coins','admin_add_owner','admin_adjust_agency_beans','admin_adjust_agency_commission','admin_adjust_balance','admin_agency_overview_stats','admin_apply_chat_punishment','admin_apply_severity_ban','admin_approve_device','admin_approve_helper_topup','admin_approve_pending_action','admin_authenticate','admin_block_agency','admin_block_user','admin_change_own_password','admin_check_device_status','admin_clear_frame_references','admin_complete_payment_transaction','admin_cost_monitor_ack_alert','admin_cost_monitor_stats','admin_country_distribution','admin_delete_party_background','admin_delete_recording','admin_delete_reel','admin_delete_user','admin_entry_effects_stats','admin_finance_overview_stats','admin_force_verify_and_approve_host','admin_game_today_stats','admin_get_my_admin_user','admin_gift_frame_to_user','admin_helper_applications_stats','admin_helper_management_stats','admin_helper_requests_stats','admin_host_applications_paginated','admin_host_stats','admin_list_auto_actions','admin_list_avatar_frames_all','admin_list_blocked_agencies','admin_list_blocked_users','admin_list_chat_bubbles_all','admin_list_chat_moderation_logs_paginated','admin_list_entry_banners_all','admin_list_face_verification_paginated','admin_list_face_violations','admin_list_gifts_all','admin_list_hosts_paginated','admin_list_live_bans','admin_list_online_users','admin_list_owners','admin_list_party_backgrounds','admin_list_pending_actions','admin_list_pending_devices','admin_list_recordings','admin_list_reels','admin_list_role_frames_all','admin_list_severity_bans','admin_list_shop_items_all','admin_list_support_reports','admin_list_topup_trader_approval_log','admin_list_topup_traders_for_approval','admin_list_user_reports','admin_live_ban_stats','admin_mark_face_submission_under_review','admin_party_management_stats','admin_payment_gateway_stats','admin_payroll_orders_stats','admin_pin_set','admin_pin_status','admin_process_face_verification','admin_process_helper_withdrawal_request','admin_process_withdrawal','admin_promote_agency_owner_to_payroll_helper','admin_record_helper_transaction_decision','admin_reject_payment_transaction','admin_reject_pending_action','admin_remove_face_verification','admin_remove_host_from_agency','admin_remove_owner','admin_reports_overview_stats','admin_request_device_access','admin_reset_phone_violation_count','admin_resolve_reel_report','admin_reverse_auto_action','admin_review_host_application','admin_revoke_device','admin_rotate_secret_token','admin_send_notification','admin_send_support_message','admin_session_block_user','admin_session_unban_live','admin_set_agency_active_status','admin_set_host_status','admin_set_section_permissions','admin_set_topup_helper_active','admin_set_topup_helper_level','admin_set_topup_trader_approval','admin_set_user_verification','admin_toggle_face_verification','admin_update_agency_level','admin_update_face_violation','admin_update_my_support_display_name','admin_update_reel_status','admin_update_support_report','admin_update_user_gender','admin_update_user_report','admin_upsert_party_background','admin_upsert_topup_helper','admin_user_stats','admin_visual_assets_stats','admin_withdrawal_stats','agency_send_diamonds_to_agency','agency_send_diamonds_to_user','approve_host_request','approve_rating_reward','approve_seat_request','ban_duplicate_face_attempt','bind_own_device_id','bump_sync_test','cancel_account_deletion','cancel_agency_request','check_rate_limit','check_session_valid','check_signup_eligibility','claim_agency_withdrawal','claim_daily_login_reward','claim_first_recharge_bonus_and_credit','claim_host_live_hour_bonus','claim_invitation_reward','claim_parcel_reward','claim_task_reward','claim_vip_daily_reward','cleanup_stale_live_streams','cleanup_stale_online_users','close_live_stream_now','consume_call_balance_reservation','create_agency_for_user','create_live_game_round','create_party_room','create_sub_agent','current_admin_id_from_header','decline_private_call','decline_seat_invitation','deduct_call_coins_per_minute','deduct_coins','deduct_coins_atomic','deduct_coins_from_user','distribute_pk_rewards','end_live_stream','end_private_call','ensure_call_e2ee_key','ensure_profile_row_from_auth','enter_live_stream','enter_party_room','exchange_user_beans_to_diamonds','ferris_wheel_play','finalize_first_minute_earnings','find_account_by_face','generate_user_parcels','get_admin_dashboard_stats','get_agency_by_code','get_agency_diamond_balance','get_agency_rankings','get_agency_transfer_history','get_conversations_with_details','get_effective_host_percent','get_game_rankings_leaderboard','get_helper_daily_topup_stats','get_host_agency_request','get_host_earnings_leaderboard','get_host_live_bonus_state','get_live_stream_ingress','get_my_host_bonus_ledger','get_popular_gift_assets','get_public_home_hosts_v2','get_public_host_countries_v1','get_public_landing_agencies','get_public_profile_presence_v1','get_top_gifters_leaderboard','get_trader_wallet_topup_rate','get_user_live_ban','get_user_notices','helper_add_diamonds_to_agency','helper_process_agency_withdrawal','helper_transfer_coins_to_user','helper_transfer_diamonds_to_agency','helper_transfer_diamonds_to_self','increment_reel_view','is_admin','is_user_live_banned','join_agency','join_live_stream_viewer','kick_party_participant','leave_live_stream_viewer','link_agency_to_parent','log_helper_payment_visibility','mark_all_notices_read','mark_call_delivered','mark_call_reconnecting','mark_messages_delivered','mark_messages_read','mark_notice_read','party_mute_seat','party_participant_heartbeat','place_game_bet','place_live_game_bet','process_contact_violation','process_game_bet','process_game_win','process_helper_order_secure','process_live_game_round','process_vip_subscription','purchase_party_background','purchase_shop_item','raise_security_alert','recalculate_all_agency_levels','recalculate_user_level','record_host_live_minute','record_invitation','record_live_violation','recover_session_by_device','refund_call_on_failed_connect','register_device_fingerprint','register_device_token','reject_host_request','reject_seat_request','release_call_balance','request_account_deletion','request_agency_withdrawal','request_pk_battle_end','reserve_call_balance','reset_my_call_status','roulette_complete_session','roulette_get_or_create_session','roulette_place_bet','roulette_spin_and_settle','search_group_by_code','search_user_by_app_uid','search_user_by_id','send_notification','set_topup_helper_listing','start_live_stream','start_pk_battle','start_private_call','submit_call_rating','submit_manual_recharge_proof','submit_private_call_rating','submit_rating_proof','support_admin_file_report','sync_host_online_status','teen_patti_play','timeout_private_call','update_active_session','update_host_call_rate','update_stream_heartbeat','update_task_progress','user_complete_instant_helper_topup','validate_session_integrity','viewer_heartbeat'];
BEGIN
  FOR fn IN
    SELECT p.oid, p.proname, pg_get_function_identity_arguments(p.oid) AS args
    FROM pg_proc p
    JOIN pg_namespace n ON n.oid = p.pronamespace
    WHERE n.nspname = 'public' AND p.prosecdef = true
  LOOP
    EXECUTE format('REVOKE EXECUTE ON FUNCTION public.%I(%s) FROM PUBLIC, anon, authenticated',
                   fn.proname, fn.args);
    IF fn.proname = ANY(whitelist) THEN
      EXECUTE format('GRANT EXECUTE ON FUNCTION public.%I(%s) TO authenticated',
                     fn.proname, fn.args);
    END IF;
  END LOOP;
END
$$;